definition.script:
pipeline {
    agent {
        docker {
            image 'maven:3.9.11-eclipse-temurin-25-noble'
            args '-v maven-repository:/root/.m2'
        }
    }
    stages {
         stage("Prepara") {
            steps {
                git 'https://github.com/jmagit/demos-devops.git'
            }
        }
        stage("Compile") {
            steps {
                sh "mvn compile"
            }
        }
        stage("Unit test") {
            steps {
                sh "mvn test"
            }
            post {
                always {
                    junit 'target/surefire-reports/*.xml'
                }
            }
        }
        // stage("SonarQube Analysis") {
        //     steps {
        //         withSonarQubeEnv('SonarQubeDockerServer') {
        //             sh 'mvn clean verify sonar:sonar'
        //         }
        //         timeout(2) { // time: 2 unit: 'MINUTES'
        //           // In case of SonarQube failure or direct timeout exceed, stop Pipeline
        //           waitForQualityGate abortPipeline: waitForQualityGate().status != 'OK'
        //         }
        //     }
        // }
        stage("Build") {
            steps {
                sh "mvn package -DskipTests"
            }
            post {
                success {
                    archiveArtifacts artifacts: 'target/*.jar', followSymlinks: false
                }
            }
        }
        stage("Deploy") {
            steps {
                sh "mvn install -DskipTests"
            }
        }
    }
    post {
        always {
             mail to: 'team@example.com',
             subject: "Finalizado Pipeline: ${currentBuild.fullDisplayName}",
             body: "Status ${currentBuild.currentResult} - Something is wrong with ${env.BUILD_URL}"
        }
    }
}
